import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Player {
  id: string;
  name: string;
  score: number;
}

export interface SportVideo {
  sport: string;
  videoId: string;
  start: number;
  end: number;
  hint: string;
}

export enum GameState {
  LOBBY = 'LOBBY',
  ROUND_START = 'ROUND_START',
  PLAYING = 'PLAYING',
  VERIFYING = 'VERIFYING',
  ROUND_RESULTS = 'ROUND_RESULTS',
  GAME_OVER = 'GAME_OVER'
}

export interface GameContext {
  players: Player[];
  currentPlayerIndex: number;
  currentRound: number;
  maxRounds: number;
  currentVideo: SportVideo | null;
  state: GameState;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function verifySportAnswer(userInput: string, targetSport: string): Promise<{ isCorrect: boolean; feedback: string }> {
  const prompt = `A user is playing a game where they identify a Winter Olympic sport. 
  The correct answer is "${targetSport}".
  The user guessed "${userInput}".
  Is the user's guess close enough to be considered correct? (e.g. "Skating" might be close for "Speed Skating" or "Figure Skating" depending on context, but be reasonably strict).
  Also provide a short 1-sentence fun fact about "${targetSport}".`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING, description: "A short fun fact or feedback about the sport." }
          },
          required: ["isCorrect", "feedback"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Gemini Error:", error);
    const simpleCheck = userInput.toLowerCase().includes(targetSport.toLowerCase()) || targetSport.toLowerCase().includes(userInput.toLowerCase());
    return { isCorrect: simpleCheck, feedback: `That's ${targetSport}! A core Winter Olympic event.` };
  }
}

export async function getGameIntroMessage(players: string[]): Promise<string> {
  const prompt = `Generate a very short, exciting 2-sentence introduction for a Winter Olympic quiz game. 
  The players are: ${players.join(', ')}. Mention the cold and the gold!`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt
    });
    return response.text;
  } catch (e) {
    return "Welcome to the Winter Games! Athletes, prepare your eyes and ears for the ultimate sport spotting challenge!";
  }
}

import React, { useState } from 'react';
import { Player } from '../types';

interface PlayerSetupProps {
  onStart: (players: Player[]) => void;
}

const PlayerSetup: React.FC<PlayerSetupProps> = ({ onStart }) => {
  const [names, setNames] = useState<string[]>(['', '']);

  const addPlayer = () => setNames([...names, '']);
  const removePlayer = (index: number) => setNames(names.filter((_, i) => i !== index));

  const handleNameChange = (index: number, val: string) => {
    const newNames = [...names];
    newNames[index] = val;
    setNames(newNames);
  };

  const handleStart = () => {
    const validNames = names.filter(n => n.trim().length > 0);
    if (validNames.length < 1) return;

    const players: Player[] = validNames.map((name, idx) => ({
      id: `p-${idx}`,
      name,
      score: 0
    }));
    onStart(players);
  };

  return (
    <div className="max-w-md w-full mx-auto p-8 glass-panel rounded-3xl animate-frost">
      <h2 className="text-4xl font-heading mb-6 text-center text-blue-300">Assemble the Athletes</h2>
      <p className="text-slate-300 mb-8 text-center">Who will represent the nations today?</p>

      <div className="space-y-4 mb-8">
        {names.map((name, idx) => (
          <div key={idx} className="flex gap-2">
            <input
              type="text"
              value={name}
              onChange={(e) => handleNameChange(idx, e.target.value)}
              placeholder={`Player ${idx + 1}`}
              className="flex-1 bg-slate-800/50 border border-slate-700 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-white"
            />
            {names.length > 1 && (
              <button 
                onClick={() => removePlayer(idx)}
                className="px-4 py-2 text-red-400 hover:text-red-300 transition-colors"
              >
                ✕
              </button>
            )}
          </div>
        ))}
      </div>

      <div className="flex flex-col gap-3">
        <button 
          onClick={addPlayer}
          className="w-full py-3 rounded-xl border border-dashed border-slate-600 text-slate-400 hover:border-blue-500 hover:text-blue-400 transition-all"
        >
          + Add Competitor
        </button>
        <button 
          onClick={handleStart}
          className="w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 rounded-xl font-bold text-lg shadow-lg shadow-blue-500/20 transform hover:-translate-y-0.5 transition-all"
        >
          Enter the Stadium
        </button>
      </div>
    </div>
  );
};

export default PlayerSetup;

import React, { useEffect, useRef } from 'react';
