import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function findSportVideo(sport: string): Promise<{ videoId: string; start: number; sourceUrl?: string }> {
  // We specifically ask for highlights or broadcast clips which are more likely to allow embedding
  const prompt = `Search for a YouTube video of the Winter Olympic sport: ${sport}. 
  CRITICAL: Look for "highlights" or "broadcast" clips as official Olympic channel videos often block embedding.
  I need the 11-character YouTube Video ID and the source URL you found.
  Return your answer in strictly valid JSON format.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            videoId: { type: Type.STRING, description: "The 11-character YouTube video ID (e.g., dQw4w9WgXcQ)." },
            start: { type: Type.NUMBER, description: "Seconds from the start to begin playback (usually 10-60)." },
            sourceUrl: { type: Type.STRING, description: "The full YouTube URL you extracted the ID from." }
          },
          required: ["videoId", "start"]
        }
      },
    });

    const result = JSON.parse(response.text.trim());

    // If the model returned grounding metadata, we should prioritize any URLs found there too
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const firstUrl = chunks?.[0]?.web?.uri;

    return {
      ...result,
      sourceUrl: result.sourceUrl || firstUrl
    };
  } catch (error) {
    console.error("Error finding video:", error);
    throw error; // Let the app handle the fallback
  }
}

export async function verifySportAnswer(userInput: string, targetSport: string): Promise<{ isCorrect: boolean; feedback: string }> {
  const prompt = `Game: Identify a Winter Olympic sport. 
  Answer: "${targetSport}".
  User Guessed: "${userInput}".
  Is this correct? (Accept variations like "Skiing" for "Alpine Skiing" or "Bobsled" for "Bobsleigh").
  Also provide a 1-sentence interesting fact about ${targetSport}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING, description: "Feedback/Fun fact." }
          },
          required: ["isCorrect", "feedback"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    const isClose = userInput.toLowerCase().includes(targetSport.toLowerCase().split(' ')[0]);
    return { isCorrect: isClose, feedback: `That's ${targetSport}!` };
  }
}

export async function getGameIntroMessage(players: string[]): Promise<string> {
  const prompt = `Exciting 2-sentence intro for a Winter Olympic game. Players: ${players.join(', ')}.`;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt
    });
    return response.text;
  } catch (e) {
    return "The stadium is ready! Let the Winter Games begin!";
  }
}

import React, { useState, useEffect, useCallback } from 'react';
import { Player, SportVideo, GameState } from './types';
import { WINTER_SPORTS_LIST, WINTER_SPORTS_VIDEOS } from './constants';
import PlayerSetup from './components/PlayerSetup';
import VideoPlayer from './components/VideoPlayer';
import { verifySportAnswer, getGameIntroMessage, findSportVideo } from './services/geminiService';

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameState, setGameState] = useState<GameState>(GameState.LOBBY);
  const [currentRound, setCurrentRound] = useState(1);
  const [maxRounds] = useState(3);
  const [currentVideo, setCurrentVideo] = useState<(SportVideo & { sourceUrl?: string }) | null>(null);
  const [timer, setTimer] = useState(30);
  const [guess, setGuess] = useState('');
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; text: string } | null>(null);
  const [introMessage, setIntroMessage] = useState<string>('');
  const [isSearching, setIsSearching] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  const startNewGame = (p: Player[]) => {
    setPlayers(p);
    setGameState(GameState.ROUND_START);
    loadIntro(p.map(pl => pl.name));
  };

  const loadIntro = async (names: string[]) => {
    const msg = await getGameIntroMessage(names);
    setIntroMessage(msg);
  };

  const startTurn = async () => {
    setIsSearching(true);
    const randomSport = WINTER_SPORTS_LIST[Math.floor(Math.random() * WINTER_SPORTS_LIST.length)];

    try {
      const videoData = await findSportVideo(randomSport);
      setCurrentVideo({
        sport: randomSport,
        videoId: videoData.videoId,
        start: videoData.start,
        end: videoData.start + 30,
        hint: '',
        sourceUrl: videoData.sourceUrl
      });
    } catch (err) {
      console.warn("Search failed, using classic library fallback...");
      // Filter videos for the specific sport if available, otherwise pick any
      const fallbacks = WINTER_SPORTS_VIDEOS.filter(v => v.sport === randomSport);
      const fallback = fallbacks.length > 0 
        ? fallbacks[0] 
        : WINTER_SPORTS_VIDEOS[Math.floor(Math.random() * WINTER_SPORTS_VIDEOS.length)];

      setCurrentVideo({ ...fallback, sport: fallback.sport });
    } finally {
      setIsSearching(false);
      setGameState(GameState.PLAYING);
      setTimer(30);
      setGuess('');
      setFeedback(null);
    }
  };

  useEffect(() => {
    let interval: number;
    if (gameState === GameState.PLAYING && timer > 0) {
      interval = window.setInterval(() => {
        setTimer((prev) => prev - 1);
      }, 1000);
    } else if (timer === 0 && gameState === GameState.PLAYING) {
      handleVerify();
    }
    return () => clearInterval(interval);
  }, [gameState, timer]);

  const handleVerify = async () => {
    if (!currentVideo || isVerifying) return;

    setIsVerifying(true);
    setGameState(GameState.VERIFYING);

    const result = await verifySportAnswer(guess, currentVideo.sport);

    setFeedback({ isCorrect: result.isCorrect, text: result.feedback });

    if (result.isCorrect) {
      const updatedPlayers = [...players];
      updatedPlayers[currentPlayerIndex].score += 10;
      setPlayers(updatedPlayers);
    }

    setIsVerifying(false);
    setGameState(GameState.ROUND_RESULTS);
  };

  const nextTurn = () => {
    const isLastPlayer = currentPlayerIndex === players.length - 1;
    if (isLastPlayer) {
      if (currentRound >= maxRounds) {
        setGameState(GameState.GAME_OVER);
      } else {
        setCurrentRound(prev => prev + 1);
        setCurrentPlayerIndex(0);
        setGameState(GameState.ROUND_START);
      }
    } else {
      setCurrentPlayerIndex(prev => prev + 1);
      setGameState(GameState.ROUND_START);
    }
  };

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 md:p-8">
      {/* Header */}
      <div className="w-full max-w-5xl flex justify-between items-center mb-8">
        <h1 className="text-4xl md:text-5xl font-heading tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-blue-200 to-indigo-400">
          WINTER GAMES <span className="text-white opacity-50">/ SPORT SPOTTER</span>
        </h1>
        {players.length > 0 && gameState !== GameState.GAME_OVER && (
          <div className="flex gap-4">
            {players.map((p, idx) => (
              <div 
                key={p.id} 
                className={`px-4 py-2 rounded-xl transition-all ${idx === currentPlayerIndex ? 'bg-blue-600 scale-110 shadow-lg shadow-blue-500/30' : 'bg-slate-800 opacity-60'}`}
              >
                <div className="text-xs font-bold uppercase tracking-widest opacity-70">{p.name}</div>
                <div className="text-xl font-heading">{p.score} <span className="text-sm">PTS</span></div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <main className="w-full max-w-4xl">
        {gameState === GameState.LOBBY && (
          <PlayerSetup onStart={startNewGame} />
        )}

        {gameState === GameState.ROUND_START && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            {isSearching ? (
              <div className="py-10">
                <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
                <h2 className="text-3xl font-heading text-blue-300">Searching Broadcast Archives...</h2>
                <p className="text-slate-400">Retrieving an embeddable clip for {currentPlayer?.name}.</p>
              </div>
            ) : (
              <>
                <div className="text-blue-400 text-sm font-bold tracking-widest uppercase mb-2">Round {currentRound} of {maxRounds}</div>
                <h2 className="text-6xl font-heading mb-6">Up Next: {currentPlayer?.name}</h2>
                <p className="text-xl text-slate-300 mb-8 italic">"{introMessage || 'Prepare yourself...'}"</p>
                <button 
                  onClick={startTurn}
                  className="px-10 py-5 bg-white text-slate-900 rounded-2xl font-bold text-xl hover:bg-blue-50 transition-all transform hover:scale-105 active:scale-95 shadow-xl shadow-white/10"
                >
                  Start Turn
                </button>
              </>
            )}
          </div>
        )}

        {gameState === GameState.PLAYING && currentVideo && (
          <div className="flex flex-col gap-6 animate-frost">
            <div className="flex justify-between items-end">
              <div>
                <div className="text-blue-400 text-sm font-bold uppercase tracking-widest">{currentPlayer.name}'s Turn</div>
                <h3 className="text-2xl font-bold">Identify the Sport</h3>
              </div>
              <div className={`text-5xl font-heading transition-colors ${timer < 10 ? 'text-red-500 animate-pulse' : 'text-blue-300'}`}>
                {timer}s
              </div>
            </div>

            <VideoPlayer video={currentVideo} isGameOver={false} />

            {currentVideo.sourceUrl && (
              <div className="text-xs text-slate-500 text-right italic">
                Source: <a href={currentVideo.sourceUrl} target="_blank" rel="noopener noreferrer" className="underline hover:text-blue-400">{currentVideo.sourceUrl}</a>
              </div>
            )}

            <div className="flex gap-4">
              <input 
                type="text" 
                autoFocus
                value={guess}
                onChange={(e) => setGuess(e.target.value)}
                placeholder="What sport is this?"
                className="flex-1 bg-slate-800/80 border border-slate-600 rounded-2xl px-6 py-4 text-xl focus:outline-none focus:ring-4 focus:ring-blue-500/50 transition-all text-white"
                onKeyDown={(e) => e.key === 'Enter' && handleVerify()}
              />
              <button 
                disabled={isVerifying}
                onClick={handleVerify}
                className="px-8 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded-2xl font-bold text-lg shadow-lg transition-all active:scale-95"
              >
                SUBMIT
              </button>
            </div>
          </div>
        )}

        {gameState === GameState.VERIFYING && (
          <div className="glass-panel p-20 rounded-3xl text-center animate-frost">
            <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
            <h2 className="text-3xl font-bold mb-2">Reviewing the Tape...</h2>
            <p className="text-slate-400">The AI judges are evaluating your answer.</p>
          </div>
        )}

        {gameState === GameState.ROUND_RESULTS && feedback && currentVideo && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            <div className={`text-7xl mb-6`}>{feedback.isCorrect ? '🏆' : '❄️'}</div>
            <h2 className={`text-5xl font-heading mb-2 ${feedback.isCorrect ? 'text-green-400' : 'text-slate-300'}`}>
              {feedback.isCorrect ? 'CORRECT!' : 'ALMOST!'}
            </h2>
            <div className="text-2xl font-bold mb-4">The sport was {currentVideo.sport}</div>
            <p className="text-lg text-slate-300 max-w-md mx-auto mb-8 bg-slate-900/50 p-6 rounded-2xl border border-slate-700 italic">
              {feedback.text}
            </p>
            <button 
              onClick={nextTurn}
              className="px-10 py-5 bg-blue-600 hover:bg-blue-500 rounded-2xl font-bold text-xl shadow-xl transition-all"
            >
              Continue
            </button>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            <h2 className="text-6xl font-heading mb-8">Final Standings</h2>
            <div className="space-y-4 mb-10">
              {[...players].sort((a, b) => b.score - a.score).map((p, idx) => (
                <div key={p.id} className="flex items-center justify-between bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                  <div className="flex items-center gap-4">
                    <span className="text-3xl font-heading text-blue-400 w-8">#{idx + 1}</span>
                    <span className="text-2xl font-bold">{p.name}</span>
                  </div>
                  <span className="text-3xl font-heading">{p.score} PTS</span>
                </div>
              ))}
            </div>
            <button 
              onClick={() => window.location.reload()}
              className="px-10 py-5 bg-white text-slate-900 rounded-2xl font-bold text-xl hover:bg-blue-50 transition-all shadow-xl"
            >
              Play Again
            </button>
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="mt-auto py-8 text-slate-500 text-xs uppercase tracking-widest font-bold text-center">
        Powered by Gemini with Search Grounding • Embed-Friendly Video Discovery
      </footer>
    </div>
  );
};

