export async function generateSportImage(sport: string): Promise<string> {
  const prompt = `A cinematic, high-action, professional photography shot of a Winter Olympic athlete performing ${sport}. 
  The scene should be epic, with snow spray, dramatic lighting, and authentic gear. 
  Avoid showing any text, logos, or identifying names of the sport in the image. 
  Style: Modern sports photography, ultra-realistic, 8k resolution.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data returned from Gemini");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
}

