  Rules: Is this guess correct? Be lenient with synonyms (e.g., "Sled" for "Bobsleigh" or "Ice Skating" for "Figure Skating"). 
  Provide a 1-sentence interesting fact about the sport.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING, description: "Feedback/Fun fact." }
          },
          required: ["isCorrect", "feedback"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    const isClose = userInput.toLowerCase().includes(targetSport.toLowerCase().split(' ')[0]);
    return { isCorrect: isClose, feedback: `That's ${targetSport}!` };
  }
}

