    if (!currentImage || isVerifying || gameState !== GameState.PLAYING) return;

    setIsVerifying(true);
    setGameState(GameState.VERIFYING);
    disconnectVoice(); // Always disconnect voice during verification transitions

    try {
      const result = await verifySportAnswer(guess, currentImage.sport);
      setFeedback({ isCorrect: result.isCorrect, text: result.feedback });

      const historyItem: HistoryItem = {
        sport: currentImage.sport,
        imageUrl: currentImage.imageUrl,
        playerName: players[currentPlayerIndex].name,
        playerGuess: guess,
        isCorrect: result.isCorrect
      };
      setHistory(prev => [...prev, historyItem]);

      if (result.isCorrect) {
        setPlayers(prev => {
          const updated = [...prev];
          updated[currentPlayerIndex].score += 10;
          return updated;
        });
      }
      setGameState(GameState.ROUND_RESULTS);
    } catch (err) {
      setFeedback({ isCorrect: false, text: `Technical error! It was ${currentImage.sport}.` });
      setGameState(GameState.ROUND_RESULTS);
    } finally {
      setIsVerifying(false);
    }
  };

  const nextTurn = () => {
    disconnectVoice();
    const isLastPlayer = currentPlayerIndex === players.length - 1;
    if (isLastPlayer) {
      if (currentRound >= maxRounds) {
        setGameState(GameState.GAME_OVER);
      } else {
        setCurrentRound(prev => prev + 1);
        setCurrentPlayerIndex(0);
        setGameState(GameState.ROUND_START);
      }
    } else {
      setCurrentPlayerIndex(prev => prev + 1);
      setGameState(GameState.ROUND_START);
    }
  };

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 md:p-8">
