                title={isVoiceActive ? 'Stop Listening' : 'Start Voice Command'}
              >
                {isVoiceActive ? (
                  <>
                    <span className="absolute inset-0 rounded-2xl bg-red-500 animate-ping opacity-25"></span>
                    <svg className="w-8 h-8 text-white relative z-10" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                  </>
                ) : (
                  <svg className="w-8 h-8 text-slate-400 group-hover:text-white transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                )}
              </button>

              <div className="flex-1 relative">
                <input 
                  type="text" 
                  autoFocus
                  value={guess}
                  onChange={(e) => setGuess(e.target.value)}
                  placeholder={isVoiceActive ? "Listening..." : "Type or Click mic to speak..."}
                  className={`w-full h-16 bg-slate-800/80 border rounded-2xl px-6 text-xl focus:outline-none focus:ring-4 transition-all text-white ${isVoiceActive ? 'border-red-500/50 focus:ring-red-500/20' : 'border-slate-600 focus:ring-blue-500/50'}`}
                  onKeyDown={(e) => e.key === 'Enter' && handleVerify()}
