                {isVoiceActive && (
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                    <span className="text-[10px] text-red-400 font-bold uppercase tracking-widest animate-pulse">Live Audio</span>
