              </div>

              <button 
                disabled={isVerifying}
                onClick={handleVerify}
                className="px-8 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded-2xl font-bold text-lg shadow-lg transition-all active:scale-95"
              >
                SUBMIT
              </button>
            </div>
            <div className="flex justify-center gap-6">
               <p className="text-[10px] text-slate-500 uppercase tracking-widest flex items-center gap-1">
                 <kbd className="bg-slate-800 px-1 rounded border border-slate-600">Mic</kbd> speak guess
               </p>
               <p className="text-[10px] text-slate-500 uppercase tracking-widest flex items-center gap-1">
                 <kbd className="bg-slate-800 px-1 rounded border border-slate-600">"Submit"</kbd> check answer
               </p>
            </div>
          </div>
        )}

        {gameState === GameState.VERIFYING && (
          <div className="glass-panel p-20 rounded-3xl text-center animate-frost">
            <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
            <h2 className="text-3xl font-bold mb-2">Reviewing the Scene...</h2>
            <p className="text-slate-400">The judges are verifying your identification.</p>
          </div>
        )}

        {gameState === GameState.ROUND_RESULTS && feedback && currentImage && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            <div className={`text-7xl mb-6`}>{feedback.isCorrect ? '🥇' : '❄️'}</div>
            <h2 className={`text-5xl font-heading mb-2 ${feedback.isCorrect ? 'text-green-400' : 'text-slate-300'}`}>
              {feedback.isCorrect ? 'SUCCESS!' : 'NOT QUITE!'}
            </h2>
            <div className="text-2xl font-bold mb-4">It was {currentImage.sport}</div>
            <div className="text-lg text-slate-300 max-w-lg mx-auto mb-8 bg-slate-900/50 p-6 rounded-2xl border border-slate-700 italic">
              {feedback.text}
            </div>
            <button onClick={nextTurn} className="px-10 py-5 bg-blue-600 hover:bg-blue-500 rounded-2xl font-bold text-xl shadow-xl transition-all">
              Continue Competition
            </button>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            <h2 className="text-6xl font-heading mb-8">Victory Ceremony</h2>
            <div className="space-y-4 mb-10">
              {[...players].sort((a, b) => b.score - a.score).map((p, idx) => (
                <div key={p.id} className="flex items-center justify-between bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
                  <div className="flex items-center gap-4">
                    <span className="text-3xl font-heading text-blue-400 w-8">#{idx + 1}</span>
                    <span className="text-2xl font-bold">{p.name}</span>
                  </div>
                  <span className="text-3xl font-heading">{p.score} PTS</span>
                </div>
              ))}
            </div>

            <div className="flex flex-col sm:flex-row gap-4 justify-center mb-12">
              <button onClick={resetMatch} className="px-10 py-5 bg-white text-slate-900 rounded-2xl font-bold text-xl hover:bg-blue-50 transition-all shadow-xl">
                Same Athletes, New Match
              </button>
              <button onClick={backToLobby} className="px-10 py-5 bg-slate-800 hover:bg-slate-700 text-white border border-slate-600 rounded-2xl font-bold text-xl transition-all">
                New Competitors
              </button>
            </div>

            <hr className="border-white/10 mb-8" />

            <HistoryGallery history={history} />
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="mt-auto py-8 text-slate-500 text-[10px] uppercase tracking-[0.2em] font-bold text-center">
        Powered by Gemini 2.5 Flash Image & Live API • Click Mic to Start Commands
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Player, SportImage, GameState, HistoryItem } from './types';
import { WINTER_SPORTS_LIST } from './constants';
import PlayerSetup from './components/PlayerSetup';
import ImageDisplay from './components/ImageDisplay';
import HistoryGallery from './components/HistoryGallery';
import { verifySportAnswer, getGameIntroMessage, generateSportImage } from './services/geminiService';

// Audio Helpers for Live API
function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const int16 = new Int16Array(data.length);
  for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameState, setGameState] = useState<GameState>(GameState.LOBBY);
  const [currentRound, setCurrentRound] = useState(1);
  const [maxRounds] = useState(3);
  const [currentImage, setCurrentImage] = useState<SportImage | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [timer, setTimer] = useState(30);
  const [guess, setGuess] = useState('');
  const [interimTranscript, setInterimTranscript] = useState('');
  const [lastVoiceCommand, setLastVoiceCommand] = useState<string | null>(null);
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; text: string } | null>(null);
  const [introMessage, setIntroMessage] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isVoiceConnecting, setIsVoiceConnecting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Refs for Live API
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const transcriptTimeoutRef = useRef<number | null>(null);

  const startNewGame = (p: Player[]) => {
    setPlayers(p);
    setHistory([]);
    setGameState(GameState.ROUND_START);
    loadIntro(p.map(pl => pl.name));
  };

  const loadIntro = async (names: string[]) => {
    try {
      const msg = await getGameIntroMessage(names);
      setIntroMessage(msg);
    } catch (e) {
      setIntroMessage("The stadium is ready! Let the Winter Games begin!");
    }
  };

  const resetMatch = () => {
    setPlayers(prev => prev.map(p => ({ ...p, score: 0 })));
    setHistory([]);
    setCurrentPlayerIndex(0);
    setCurrentRound(1);
    setGameState(GameState.ROUND_START);
    setFeedback(null);
    setCurrentImage(null);
    setError(null);
    setInterimTranscript('');
  };

  const backToLobby = () => {
    setPlayers([]);
    setHistory([]);
    setCurrentPlayerIndex(0);
    setCurrentRound(1);
    setGameState(GameState.LOBBY);
    setFeedback(null);
    setCurrentImage(null);
    setError(null);
    setInterimTranscript('');
  };

  // Voice Connection Logic
  const toggleVoice = async () => {
    if (sessionRef.current) {
      disconnectVoice();
      return;
    }

    setIsVoiceConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioContext;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsVoiceActive(true);
            setIsVoiceConnecting(false);
            const source = audioContext.createMediaStreamSource(stream);
            const scriptProcessor = audioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContext.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              if (!text) return;

              const lowerText = text.toLowerCase().trim();

              // Visual "Typing" Feedback
              setInterimTranscript(text);

              // Clear previous "typing" timeout
              if (transcriptTimeoutRef.current) window.clearTimeout(transcriptTimeoutRef.current);

              // Handle Voice Commands
              if (lowerText.includes("submit") || lowerText.includes("check")) {
                setLastVoiceCommand("SUBMITTING...");
                setTimeout(() => handleVerify(), 500);
              } else if (lowerText.includes("next") || lowerText.includes("continue")) {
                setLastVoiceCommand("CONTINUING...");
                setTimeout(() => {
                   if (gameState === GameState.ROUND_RESULTS) nextTurn();
                   else if (gameState === GameState.ROUND_START) startTurn();
                   setLastVoiceCommand(null);
                }, 800);
              } else {
                // If it's just text, wait for a pause to commit it to the main guess box
                transcriptTimeoutRef.current = window.setTimeout(() => {
                  setGuess(prev => {
                    const combined = (prev + ' ' + text).trim();
                    return combined.charAt(0).toUpperCase() + combined.slice(1);
                  });
                  setInterimTranscript('');
                }, 1000);
              }
            }
          },
          onclose: () => {
            setIsVoiceActive(false);
            setIsVoiceConnecting(false);
          },
          onerror: () => {
            setIsVoiceActive(false);
            setIsVoiceConnecting(false);
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are a winter sports game host. Help transcribe the users winter sport guesses. If they say "Submit" or "Continue", transcribe them clearly. If they guess a sport, transcribe JUST the name of the sport as they say it.',
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (e) {
      console.error("Voice connection failed", e);
      setIsVoiceConnecting(false);
    }
  };

  const disconnectVoice = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    setIsVoiceActive(false);
    setIsVoiceConnecting(false);
    setInterimTranscript('');
  };

  const startTurn = async () => {
    setIsGenerating(true);
    setError(null);
    setGuess('');
    setInterimTranscript('');
    const randomSport = WINTER_SPORTS_LIST[Math.floor(Math.random() * WINTER_SPORTS_LIST.length)];

    try {
      const imageUrl = await generateSportImage(randomSport);
      setCurrentImage({
        sport: randomSport,
        imageUrl: imageUrl,
        hint: ''
      });
      setGameState(GameState.PLAYING);
      setTimer(30);
      setFeedback(null);
    } catch (err) {
      setError("The AI judge failed to paint the scene. Please try again.");
      setGameState(GameState.ERROR);
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    let interval: number;
    if (gameState === GameState.PLAYING && timer > 0) {
      interval = window.setInterval(() => {
        setTimer((prev) => prev - 1);
      }, 1000);
    } else if (timer === 0 && gameState === GameState.PLAYING) {
      handleVerify();
    }
    return () => clearInterval(interval);
  }, [gameState, timer]);

  const handleVerify = async () => {
    if (!currentImage || isVerifying || gameState !== GameState.PLAYING) return;

    setIsVerifying(true);
    setGameState(GameState.VERIFYING);
    setLastVoiceCommand(null);
    disconnectVoice(); 

    try {
      const result = await verifySportAnswer(guess || interimTranscript, currentImage.sport);
      setFeedback({ isCorrect: result.isCorrect, text: result.feedback });

      const historyItem: HistoryItem = {
        sport: currentImage.sport,
        imageUrl: currentImage.imageUrl,
        playerName: players[currentPlayerIndex].name,
        playerGuess: guess || interimTranscript,
        isCorrect: result.isCorrect
      };
      setHistory(prev => [...prev, historyItem]);

      if (result.isCorrect) {
        setPlayers(prev => {
          const updated = [...prev];
          updated[currentPlayerIndex].score += 10;
          return updated;
        });
      }
      setGameState(GameState.ROUND_RESULTS);
    } catch (err) {
      setFeedback({ isCorrect: false, text: `Technical error! It was ${currentImage.sport}.` });
      setGameState(GameState.ROUND_RESULTS);
    } finally {
      setIsVerifying(false);
    }
  };

  const nextTurn = () => {
    disconnectVoice();
    const isLastPlayer = currentPlayerIndex === players.length - 1;
    if (isLastPlayer) {
      if (currentRound >= maxRounds) {
        setGameState(GameState.GAME_OVER);
      } else {
        setCurrentRound(prev => prev + 1);
        setCurrentPlayerIndex(0);
        setGameState(GameState.ROUND_START);
      }
    } else {
      setCurrentPlayerIndex(prev => prev + 1);
      setGameState(GameState.ROUND_START);
    }
  };

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 md:p-8 overflow-x-hidden">
      {/* Header */}
      <div className="w-full max-w-5xl flex justify-between items-center mb-8">
        <h1 className="text-4xl md:text-5xl font-heading tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-blue-200 to-indigo-400">
          WINTER GAMES <span className="text-white opacity-50">/ SPORT SPOTTER</span>
        </h1>
        {players.length > 0 && gameState !== GameState.LOBBY && (
          <div className="flex gap-4">
            {players.map((p, idx) => (
              <div 
                key={p.id} 
                className={`px-4 py-2 rounded-xl transition-all border ${idx === currentPlayerIndex ? 'bg-blue-600 border-blue-400 scale-110 shadow-lg shadow-blue-500/30' : 'bg-slate-800/40 border-transparent opacity-60'}`}
              >
                <div className="text-xs font-bold uppercase tracking-widest opacity-70">{p.name}</div>
                <div className="text-xl font-heading leading-none mt-1">{p.score} <span className="text-xs opacity-60">PTS</span></div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <main className="w-full max-w-4xl relative">
        {gameState === GameState.LOBBY && (
          <PlayerSetup onStart={startNewGame} />
        )}

        {gameState === GameState.ERROR && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost border-red-500/50">
            <div className="text-6xl mb-4">⚠️</div>
            <h2 className="text-3xl font-heading text-red-400 mb-4">Event Postponed</h2>
            <p className="text-slate-300 mb-8 max-w-sm mx-auto">{error}</p>
            <button onClick={startTurn} className="px-8 py-4 bg-red-600 hover:bg-red-500 rounded-xl font-bold shadow-lg transition-all">
              Try to Reconnect
            </button>
          </div>
        )}

        {gameState === GameState.ROUND_START && (
          <div className="glass-panel p-12 rounded-3xl text-center animate-frost">
            {isGenerating ? (
              <div className="py-10">
                <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
                <h2 className="text-3xl font-heading text-blue-300">Generating the Challenge...</h2>
                <p className="text-slate-400 italic">The AI is painting a scene for {currentPlayer?.name}.</p>
              </div>
            ) : (
              <>
                <div className="text-blue-400 text-sm font-bold tracking-widest uppercase mb-2">Round {currentRound} of {maxRounds}</div>
                <h2 className="text-6xl font-heading mb-6">Athlete: {currentPlayer?.name}</h2>
                <p className="text-xl text-slate-300 mb-8 italic px-4">"{introMessage || 'The arena is cold and ready...'}"</p>
                <div className="flex flex-col items-center gap-4">
                  <button onClick={startTurn} className="px-12 py-5 bg-white text-slate-900 rounded-2xl font-bold text-xl hover:bg-blue-50 transition-all transform hover:scale-105 active:scale-95 shadow-xl shadow-white/10">
                    Enter the Arena
                  </button>
                </div>
              </>
            )}
          </div>
        )}

        {gameState === GameState.PLAYING && currentImage && (
          <div className="flex flex-col gap-6 animate-frost">
            <div className="flex justify-between items-end">
              <div>
                <div className="flex items-center gap-2">
                  <div className="text-blue-400 text-sm font-bold uppercase tracking-widest">{currentPlayer.name}'s Turn</div>
                </div>
                <h3 className="text-2xl font-bold italic">Identify this Winter Sport:</h3>
              </div>
              <div className={`text-5xl font-heading transition-colors ${timer < 10 ? 'text-red-500 animate-pulse' : 'text-blue-300'}`}>
                {timer}s
              </div>
            </div>

            <ImageDisplay imageUrl={currentImage.imageUrl} />

            <div className="relative">
              {lastVoiceCommand && (
                <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-blue-500 text-white px-4 py-1 rounded-full font-bold text-xs animate-bounce shadow-lg">
                  {lastVoiceCommand}
