import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Player, SportImage, GameState, HistoryItem } from './types';
import { WINTER_SPORTS_LIST } from './constants';
import PlayerSetup from './components/PlayerSetup';
import HistoryGallery from './components/HistoryGallery';
import { verifySportAnswer, getGameIntroMessage, generateSportVideo } from './services/geminiService';

// Audio Helpers
function encode(bytes: Uint8Array) {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const int16 = new Int16Array(data.length);
  for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameState, setGameState] = useState<GameState>(GameState.LOBBY);
  const [currentRound, setCurrentRound] = useState(1);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [currentSport, setCurrentSport] = useState<string>('');
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [timer, setTimer] = useState(30);
  const [guess, setGuess] = useState('');
  const [typedFeedback, setTypedFeedback] = useState(''); // The animated typing state
  const [lastVoiceCommand, setLastVoiceCommand] = useState<string | null>(null);
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; text: string } | null>(null);
  const [introMessage, setIntroMessage] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isVoiceConnecting, setIsVoiceConnecting] = useState(false);
  const [micLevel, setMicLevel] = useState(0);
  const [activeMicLabel, setActiveMicLabel] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const typingIntervalRef = useRef<number | null>(null);

  // Typewriter effect logic
  const animateTyping = (text: string) => {
    if (typingIntervalRef.current) clearInterval(typingIntervalRef.current);
    let i = 0;
    setTypedFeedback('');
    typingIntervalRef.current = window.setInterval(() => {
      if (i < text.length) {
        setTypedFeedback(prev => prev + text.charAt(i));
        i++;
      } else {
        clearInterval(typingIntervalRef.current!);
      }
    }, 40); // 40ms per letter for that "working" feel
  };

  const startNewGame = (p: Player[]) => {
    setPlayers(p);
    setGameState(GameState.ROUND_START);
    getGameIntroMessage(p.map(pl => pl.name)).then(setIntroMessage);
  };

  const toggleVoice = async () => {
    if (sessionRef.current) {
      disconnectVoice();
      return;
    }

    setIsVoiceConnecting(true);
    setError(null);

    try {
      // SMART FALLBACK LOGIC
      const devices = await navigator.mediaDevices.enumerateDevices();
      const audioDevices = devices.filter(d => d.kind === 'audioinput');

      let stream: MediaStream | null = null;

      // Try default first, but if it's the notorious "iPhone" mic on Mac, it might hang
      // We prioritize "Built-in" or "Internal" labels for stability
      const internalMic = audioDevices.find(d => 
        d.label.toLowerCase().includes('internal') || 
        d.label.toLowerCase().includes('built-in')
      );

      try {
        const constraints = internalMic 
          ? { audio: { deviceId: { exact: internalMic.deviceId } } } 
          : { audio: true };
        stream = await navigator.mediaDevices.getUserMedia(constraints);
      } catch (e) {
        console.warn("First mic attempt failed, trying fallback...", e);
        // Last resort: any working mic
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      }

      if (!stream) throw new Error("No usable microphone found.");

      const audioTrack = stream.getAudioTracks()[0];
      setActiveMicLabel(audioTrack.label);
      streamRef.current = stream;

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      await audioContext.resume();
      audioContextRef.current = audioContext;

      // Simple Analyzer for the visual volume bar
      const analyzer = audioContext.createAnalyser();
      const source = audioContext.createMediaStreamSource(stream);
      source.connect(analyzer);
      const dataArray = new Uint8Array(analyzer.frequencyBinCount);

      const updateVolume = () => {
        if (!isVoiceActive) return;
        analyzer.getByteFrequencyData(dataArray);
        const avg = dataArray.reduce((a, b) => a + b) / dataArray.length;
        setMicLevel(avg);
        requestAnimationFrame(updateVolume);
      };

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsVoiceActive(true);
            setIsVoiceConnecting(false);
            updateVolume();
            const scriptProcessor = audioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContext.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
              const text = msg.serverContent.inputTranscription.text;
              if (!text) return;

              // Visual Feedback: Start typing animation
              animateTyping(text);

              const lower = text.toLowerCase();
              if (lower.includes("submit") || lower.includes("check")) {
                setLastVoiceCommand("SUBMITTING...");
                setTimeout(handleVerify, 800);
              } else {
                setGuess(text);
              }
            }
          },
          onclose: () => disconnectVoice(),
          onerror: () => disconnectVoice(),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (e: any) {
      setIsVoiceConnecting(false);
      setError(`Hardware Error: ${e.message || "Could not access Microphone"}. Please switch from iPhone Mic to Internal Mic in System Settings.`);
    }
  };

  const disconnectVoice = () => {
    sessionRef.current?.close();
    sessionRef.current = null;
    audioContextRef.current?.close();
    audioContextRef.current = null;
    streamRef.current?.getTracks().forEach(t => t.stop());
    streamRef.current = null;
    setIsVoiceActive(false);
    setIsVoiceConnecting(false);
    setMicLevel(0);
  };

  const startTurn = async () => {
    setIsGenerating(true);
    setError(null);
    setGuess('');
    setTypedFeedback('');
    setVideoUrl(null);
    const sport = WINTER_SPORTS_LIST[Math.floor(Math.random() * WINTER_SPORTS_LIST.length)];
    setCurrentSport(sport);

    try {
      const url = await generateSportVideo(sport);
      setVideoUrl(url);
      setGameState(GameState.PLAYING);
      setTimer(30);
    } catch (err) {
      setError("Event postponed: AI video generation failed.");
      setGameState(GameState.ERROR);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleVerify = async () => {
    if (isVerifying || gameState !== GameState.PLAYING) return;
    setIsVerifying(true);
    setGameState(GameState.VERIFYING);
    disconnectVoice();

    try {
      const finalGuess = guess || typedFeedback;
      const result = await verifySportAnswer(finalGuess, currentSport);
      setFeedback({ isCorrect: result.isCorrect, text: result.feedback });
      setHistory(prev => [...prev, {
        sport: currentSport,
        imageUrl: '', // We use video now
        playerName: players[currentPlayerIndex].name,
        playerGuess: finalGuess,
        isCorrect: result.isCorrect
      }]);
      if (result.isCorrect) setPlayers(prev => {
        const up = [...prev];
        up[currentPlayerIndex].score += 10;
        return up;
      });
      setGameState(GameState.ROUND_RESULTS);
    } catch (err) {
      setGameState(GameState.ERROR);
    } finally {
      setIsVerifying(false);
    }
  };

  useEffect(() => {
    if (gameState === GameState.PLAYING && timer > 0) {
      const id = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(id);
    } else if (timer === 0 && gameState === GameState.PLAYING) {
      handleVerify();
    }
  }, [gameState, timer]);

  const nextTurn = () => {
    const isLast = currentPlayerIndex === players.length - 1;
    if (isLast) {
      if (currentRound >= 3) setGameState(GameState.GAME_OVER);
      else { setCurrentRound(r => r + 1); setCurrentPlayerIndex(0); setGameState(GameState.ROUND_START); }
    } else {
      setCurrentPlayerIndex(idx => idx + 1);
      setGameState(GameState.ROUND_START);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-white flex flex-col items-center p-4">
      {/* Header */}
      <div className="w-full max-w-4xl flex justify-between items-center py-6">
        <h1 className="text-3xl font-heading tracking-widest text-blue-400">WINTER GAMES</h1>
        <div className="flex gap-2">
          {players.map((p, i) => (
            <div key={p.id} className={`px-4 py-2 rounded-xl border transition-all ${i === currentPlayerIndex ? 'border-blue-500 bg-blue-500/20' : 'border-slate-800'}`}>
              <span className="text-xs block font-bold opacity-50">{p.name}</span>
              <span className="text-lg font-heading">{p.score}</span>
            </div>
          ))}
        </div>
      </div>

      <main className="w-full max-w-3xl flex-1 flex flex-col justify-center">
        {error && (
          <div className="bg-red-500/20 border border-red-500 p-4 rounded-2xl mb-6 animate-pulse text-center text-sm font-bold">
            {error}
          </div>
        )}

        {gameState === GameState.LOBBY && <PlayerSetup onStart={startNewGame} />}

        {gameState === GameState.ROUND_START && (
          <div className="text-center glass-panel p-12 rounded-3xl animate-frost">
            {isGenerating ? (
              <div className="space-y-4">
                <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                <p className="text-blue-300 font-heading text-xl">Creating Video Challenge...</p>
              </div>
            ) : (
              <>
                <h2 className="text-5xl font-heading mb-4">{players[currentPlayerIndex]?.name}'s Turn</h2>
                <p className="text-slate-400 mb-8">"{introMessage}"</p>
                <button onClick={startTurn} className="px-10 py-4 bg-white text-black font-bold rounded-2xl hover:bg-blue-50 transition-all">
                  Start Video
                </button>
              </>
            )}
          </div>
        )}

        {gameState === GameState.PLAYING && videoUrl && (
          <div className="space-y-6 animate-frost">
            <div className="relative aspect-video rounded-3xl overflow-hidden border-4 border-slate-800 shadow-2xl">
              <video src={videoUrl} autoPlay loop muted className="w-full h-full object-cover" />
              <div className="absolute top-4 right-4 text-4xl font-heading text-blue-400 bg-black/40 px-4 py-1 rounded-2xl backdrop-blur-md">
                {timer}s
              </div>
            </div>

            <div className="relative space-y-4">
              {lastVoiceCommand && (
                <div className="absolute -top-10 left-1/2 -translate-x-1/2 text-blue-400 font-bold text-xs animate-bounce">
                  {lastVoiceCommand}
                </div>
              )}

              <div className="flex gap-3">
                <div className="flex flex-col gap-2">
                  <button 
                    onClick={toggleVoice}
                    className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all ${isVoiceActive ? 'bg-red-500 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}
                  >
                    <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24"><path d="M12 14c1.66 0 3-1.34 3-3V5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3z"/><path d="M17 11c0 2.76-2.24 5-5 5s-5-2.24-5-5H5c0 3.53 2.61 6.43 6 6.92V21h2v-3.08c3.39-.49 6-3.39 6-6.92h-2z"/></svg>
                  </button>
                  {isVoiceActive && (
                    <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-400" style={{ width: `${Math.min(100, (micLevel / 128) * 100)}%` }}></div>
                    </div>
                  )}
                </div>

                <div className="flex-1 relative">
                  <input 
                    type="text"
                    value={typedFeedback || guess}
                    onChange={(e) => setGuess(e.target.value)}
                    placeholder={isVoiceActive ? "Transcribing your voice..." : "Click mic to speak answer"}
                    className={`w-full h-16 bg-slate-900 border rounded-2xl px-6 text-xl transition-all focus:ring-4 focus:ring-blue-500/20 ${isVoiceActive ? 'border-blue-500' : 'border-slate-800'}`}
                  />
                  {isVoiceActive && (
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-1">
                      <span className="w-1 h-1 bg-blue-400 rounded-full animate-bounce"></span>
                      <span className="w-1 h-1 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                      <span className="w-1 h-1 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                    </div>
                  )}
                  {activeMicLabel && isVoiceActive && (
                    <div className="absolute -bottom-5 left-0 text-[8px] uppercase tracking-widest text-slate-500">
                      Active: {activeMicLabel}
                    </div>
                  )}
                </div>

                <button onClick={handleVerify} className="px-8 bg-blue-600 rounded-2xl font-bold hover:bg-blue-500 active:scale-95 transition-all">
                  SUBMIT
                </button>
              </div>
              <p className="text-[10px] text-center text-slate-500 tracking-widest">SAY "SUBMIT" TO AUTOMATICALLY CHECK YOUR GUESS</p>
            </div>
          </div>
        )}

        {gameState === GameState.VERIFYING && (
          <div className="text-center p-20 glass-panel rounded-3xl animate-frost">
             <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
             <h2 className="text-2xl font-bold">The Judges are Reviewing...</h2>
          </div>
        )}

        {gameState === GameState.ROUND_RESULTS && feedback && (
          <div className="text-center glass-panel p-12 rounded-3xl animate-frost">
            <div className="text-7xl mb-4">{feedback.isCorrect ? '🥇' : '❄️'}</div>
            <h2 className={`text-4xl font-heading mb-2 ${feedback.isCorrect ? 'text-green-400' : 'text-slate-300'}`}>
              {feedback.isCorrect ? 'STRIKE!' : 'MISSED!'}
            </h2>
            <p className="text-xl font-bold mb-4">Target: {currentSport}</p>
            <p className="bg-slate-900 p-6 rounded-2xl border border-slate-800 text-slate-300 italic mb-8">{feedback.text}</p>
            <button onClick={nextTurn} className="px-12 py-4 bg-blue-600 rounded-2xl font-bold text-xl hover:bg-blue-500 transition-all">
              Continue
            </button>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="text-center glass-panel p-12 rounded-3xl animate-frost">
            <h2 className="text-5xl font-heading mb-8">Match Highlights</h2>
            <div className="space-y-2 mb-10">
              {players.sort((a,b) => b.score - a.score).map((p,i) => (
                <div key={p.id} className="flex justify-between p-4 bg-slate-900 rounded-xl">
                  <span className="font-bold text-blue-400">#{i+1} {p.name}</span>
                  <span className="font-heading">{p.score} PTS</span>
                </div>
              ))}
            </div>
            <button onClick={() => window.location.reload()} className="px-12 py-4 bg-white text-black font-bold rounded-2xl">
              Play Again
            </button>
            <HistoryGallery history={history} />
          </div>
        )}
      </main>

      <footer className="py-6 text-[8px] tracking-[0.3em] text-slate-600 uppercase font-bold">
        Smart Fallback Active • Typewriter Visuals ON • Veo Video Engine
      </footer>
    </div>
  );
};

