import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a short high-action video clip using Veo model.
 */
export async function generateSportVideo(sport: string): Promise<string> {
  const prompt = `A cinematic, high-action, professional video of a Winter Olympic athlete performing ${sport}. 
  Extreme close-ups, snow spray flying towards the camera, dramatic lighting, authentic gear. 
  NO text, NO logos. High-end sports broadcast quality. 720p resolution, high frame rate.`;

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    // Poll for the video completion
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 3000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video generation failed: No link received.");

    // Fetch the MP4 bytes with the API key
    const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const videoBlob = await videoResponse.blob();
    return URL.createObjectURL(videoBlob);
  } catch (error) {
    console.error("Error generating video:", error);
    // Return a static image fallback if Veo fails
    throw error;
  }
}

export async function verifySportAnswer(userInput: string, targetSport: string): Promise<{ isCorrect: boolean; feedback: string }> {
  const prompt = `Game: Identify a Winter Olympic sport. 
  Correct Sport: "${targetSport}".
  User Answer: "${userInput}".
  Rules: Is this guess correct? Be lenient with synonyms. 
  Provide a 1-sentence interesting fact about the sport.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isCorrect: { type: Type.BOOLEAN },
            feedback: { type: Type.STRING }
          },
          required: ["isCorrect", "feedback"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    const isClose = userInput.toLowerCase().includes(targetSport.toLowerCase().split(' ')[0]);
    return { isCorrect: isClose, feedback: `That's ${targetSport}!` };
  }
}

