import { GoogleGenAI, Type } from "@google/genai";

/**
 * Generates an action photograph using the Gemini 2.5 Flash Image model.
 */
export async function generateSportImage(sport: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `A cinematic action photograph of a Winter Olympic athlete performing ${sport}. 
  Professional sports photography, snow spray, high speed, authentic gear. 
  Sharp focus, realistic lighting. No text, no logos.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) {
      throw new Error("No image data returned from Gemini.");
    }

    return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
  } catch (error: any) {
    console.error("Error generating image:", error);
    throw error;
  }
}

export interface VerificationResult {
  isCorrect: boolean;
  feedback: string;
  detailedDescription: string;
  videoUrl?: string;
}

export async function verifySportAnswer(userInput: string, targetSport: string): Promise<VerificationResult> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // We use googleSearch to find a YouTube video link and detailed info.
  // Note: responseSchema is not allowed when using googleSearch tool.
  const prompt = `Game: Identify a Winter Olympic sport. 
  Target Sport: "${targetSport}".
  User Guess: "${userInput}".

  TASK:
  1. Determine if the guess is correct (be lenient with synonyms).
  2. Provide a short punchy feedback sentence.
  3. Provide a detailed 3-4 sentence historical and technical description of the sport.
  4. Search for a high-quality official YouTube video link for this sport's Olympic highlights.

  FORMAT YOUR RESPONSE EXACTLY LIKE THIS (delimited by |):
  STATUS: [CORRECT or INCORRECT] | FEEDBACK: [Short Sentence] | DESCRIPTION: [Detailed Description]`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";
    const parts = text.split('|');

    let isCorrect = text.toUpperCase().includes('STATUS: CORRECT');
    let feedback = "The judges have spoken!";
    let detailedDescription = "A fascinating Winter Olympic event with a rich history of competition and skill.";

    parts.forEach(p => {
      if (p.includes('FEEDBACK:')) feedback = p.replace('FEEDBACK:', '').trim();
      if (p.includes('DESCRIPTION:')) detailedDescription = p.replace('DESCRIPTION:', '').trim();
    });

    // Extract YouTube link from grounding metadata
    let videoUrl = undefined;
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const youtubeLink = groundingChunks.find(chunk => 
        chunk.web?.uri?.includes('youtube.com') || chunk.web?.uri?.includes('youtu.be')
      );
      if (youtubeLink?.web?.uri) {
        videoUrl = youtubeLink.web.uri;
      } else if (groundingChunks[0]?.web?.uri) {
        // Fallback to first grounding link if no explicit YouTube found
        videoUrl = groundingChunks[0].web.uri;
      }
    }

    return {
      isCorrect,
      feedback,
      detailedDescription,
      videoUrl
    };
  } catch (error) {
    console.error("Verification error:", error);
    const isClose = userInput.toLowerCase().includes(targetSport.toLowerCase().split(' ')[0]);
    return { 
      isCorrect: isClose, 
      feedback: `The judges say: It's ${targetSport}!`,
      detailedDescription: `This is ${targetSport}, one of the most exciting events in the Winter Games. It requires immense skill, precision, and years of dedicated training.`
    };
  }
}

export async function getGameIntroMessage(players: string[]): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Exciting 1-sentence intro for a Winter Olympic guessing game. Mention players: ${players.join(', ')}. Keep it sporty and cold!`;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt
    });
    return response.text;
  } catch (e) {
    return "The arena is set! Athletes, prepare to identify these frosty scenes!";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Player, SportImage, GameState, HistoryItem } from './types';
import { WINTER_SPORTS_LIST } from './constants';
import PlayerSetup from './components/PlayerSetup';
import HistoryGallery from './components/HistoryGallery';
import ImageDisplay from './components/ImageDisplay';
import { verifySportAnswer, getGameIntroMessage, generateSportImage, VerificationResult } from './services/geminiService';

// Audio Encoding for Live API
function encode(bytes: Uint8Array) {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}

// Audio Blob Creation for Live API
function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const int16 = new Int16Array(data.length);
  for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameState, setGameState] = useState<GameState>(GameState.LOBBY);
  const [currentRound, setCurrentRound] = useState(1);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [currentSport, setCurrentSport] = useState<string>('');
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [timer, setTimer] = useState(30);
  const [guess, setGuess] = useState('');
  const [typedFeedback, setTypedFeedback] = useState('');
  const [lastVoiceCommand, setLastVoiceCommand] = useState<string | null>(null);
  const [feedback, setFeedback] = useState<VerificationResult | null>(null);
  const [introMessage, setIntroMessage] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isVoiceConnecting, setIsVoiceConnecting] = useState(false);
  const [micLevel, setMicLevel] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const typingIntervalRef = useRef<number | null>(null);

  const animateTyping = (text: string) => {
    if (typingIntervalRef.current) clearInterval(typingIntervalRef.current);
    let i = 0;
    setTypedFeedback('');
    typingIntervalRef.current = window.setInterval(() => {
      if (i < text.length) {
        setTypedFeedback(prev => prev + text.charAt(i));
        i++;
      } else {
        clearInterval(typingIntervalRef.current!);
      }
    }, 30);
  };

  const startNewGame = (p: Player[]) => {
    setPlayers(p);
    setGameState(GameState.ROUND_START);
    getGameIntroMessage(p.map(pl => pl.name)).then(setIntroMessage);
  };

  const toggleVoice = async () => {
    if (sessionRef.current) {
      disconnectVoice();
      return;
    }

    setIsVoiceConnecting(true);
    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      if (!stream) throw new Error("No microphone found.");
      streamRef.current = stream;

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      await audioContext.resume();
      audioContextRef.current = audioContext;

      const analyzer = audioContext.createAnalyser();
      const source = audioContext.createMediaStreamSource(stream);
      source.connect(analyzer);
      const dataArray = new Uint8Array(analyzer.frequencyBinCount);

      const updateVolume = () => {
        if (!isVoiceActive && !isVoiceConnecting) return;
        analyzer.getByteFrequencyData(dataArray);
        const avg = dataArray.reduce((a, b) => a + b) / dataArray.length;
        setMicLevel(avg);
        requestAnimationFrame(updateVolume);
      };

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsVoiceActive(true);
            setIsVoiceConnecting(false);
            updateVolume();
            const scriptProcessor = audioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContext.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
              const text = msg.serverContent.inputTranscription.text;
              if (!text) return;
              animateTyping(text);
              const lower = text.toLowerCase();
              if (lower.includes("submit") || lower.includes("check")) {
                setLastVoiceCommand("CHECKING...");
                setTimeout(handleVerify, 800);
              } else {
                setGuess(text);
              }
            }
          },
          onclose: () => disconnectVoice(),
          onerror: () => disconnectVoice(),
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (e: any) {
      setIsVoiceConnecting(false);
      setError(`Audio Error: ${e.message}.`);
    }
  };

  const disconnectVoice = () => {
    sessionRef.current?.close();
    sessionRef.current = null;
    audioContextRef.current?.close();
    audioContextRef.current = null;
    streamRef.current?.getTracks().forEach(t => t.stop());
    streamRef.current = null;
    setIsVoiceActive(false);
    setIsVoiceConnecting(false);
    setMicLevel(0);
  };

  const startTurn = async () => {
    setIsGenerating(true);
    setError(null);
    setGuess('');
    setTypedFeedback('');
    setImageUrl(null);
    const sport = WINTER_SPORTS_LIST[Math.floor(Math.random() * WINTER_SPORTS_LIST.length)];
    setCurrentSport(sport);

    try {
      const url = await generateSportImage(sport);
      setImageUrl(url);
      setGameState(GameState.PLAYING);
      setTimer(30);
    } catch (err: any) {
      if (err.message?.includes("429") || err.message?.includes("quota")) {
        setError("The stadium is at capacity (Rate Limit). Please wait a moment and try again.");
      } else {
        setError("AI challenge generation failed. Let's try another event.");
      }
      setGameState(GameState.ROUND_START);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleVerify = async () => {
    if (isVerifying || gameState !== GameState.PLAYING) return;
    setIsVerifying(true);
    setGameState(GameState.VERIFYING);
    disconnectVoice();

    try {
      const finalGuess = guess || typedFeedback;
      const result = await verifySportAnswer(finalGuess, currentSport);
      setFeedback(result);

      setHistory(prev => [...prev, {
        sport: currentSport,
        imageUrl: imageUrl || '',
        playerName: players[currentPlayerIndex].name,
        playerGuess: finalGuess,
        isCorrect: result.isCorrect,
        detailedDescription: result.detailedDescription,
        videoUrl: result.videoUrl
      }]);

      if (result.isCorrect) setPlayers(prev => {
        const up = [...prev];
        up[currentPlayerIndex].score += 10;
        return up;
      });
      setGameState(GameState.ROUND_RESULTS);
    } catch (err) {
      setGameState(GameState.ERROR);
    } finally {
      setIsVerifying(false);
    }
  };

  useEffect(() => {
    if (gameState === GameState.PLAYING && timer > 0) {
      const id = setInterval(() => setTimer(t => t - 1), 1000);
      return () => clearInterval(id);
    } else if (timer === 0 && gameState === GameState.PLAYING) {
      handleVerify();
    }
  }, [gameState, timer]);

  const nextTurn = () => {
    const isLast = currentPlayerIndex === players.length - 1;
    if (isLast) {
      if (currentRound >= 3) setGameState(GameState.GAME_OVER);
      else { 
        setCurrentRound(r => r + 1); 
        setCurrentPlayerIndex(0); 
        setGameState(GameState.ROUND_START); 
      }
    } else {
      setCurrentPlayerIndex(idx => idx + 1);
      setGameState(GameState.ROUND_START);
    }
  };

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen bg-[#020617] text-white flex flex-col items-center p-4">
      {/* Header */}
      <div className="w-full max-w-4xl flex justify-between items-center py-6">
        <h1 className="text-3xl font-heading tracking-widest text-blue-400">WINTER GAMES</h1>
        <div className="flex gap-2">
          {players.map((p, i) => (
            <div key={p.id} className={`px-4 py-2 rounded-xl border transition-all ${i === currentPlayerIndex ? 'border-blue-500 bg-blue-500/20 shadow-lg shadow-blue-500/10' : 'border-slate-800 opacity-60'}`}>
              <span className="text-[10px] block font-bold opacity-50 uppercase tracking-widest">{p.name}</span>
              <span className="text-xl font-heading leading-tight">{p.score} <span className="text-[10px] opacity-40">PTS</span></span>
            </div>
          ))}
        </div>
      </div>

      <main className="w-full max-w-3xl flex-1 flex flex-col justify-center pb-12">
        {error && (
          <div className="bg-red-500/10 border border-red-500/30 p-4 rounded-2xl mb-6 animate-pulse text-center text-sm font-bold text-red-300 shadow-lg">
            {error}
          </div>
        )}

        {gameState === GameState.LOBBY && <PlayerSetup onStart={startNewGame} />}

        {gameState === GameState.ROUND_START && (
          <div className="text-center glass-panel p-12 rounded-3xl animate-frost border-white/5 shadow-2xl">
            {isGenerating ? (
              <div className="space-y-6 py-8">
                <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto shadow-lg shadow-blue-500/20"></div>
                <p className="text-blue-300 font-heading text-2xl tracking-widest uppercase animate-pulse">Generating Action Shot...</p>
              </div>
            ) : (
              <>
                <div className="text-blue-400 text-xs font-bold uppercase tracking-[0.4em] mb-4 bg-blue-500/10 inline-block px-4 py-1 rounded-full border border-blue-500/20">Round {currentRound} / 3</div>
                <h2 className="text-5xl md:text-6xl font-heading mb-4 text-white uppercase tracking-tight">{currentPlayer?.name}'s Event</h2>
                <p className="text-slate-400 mb-10 italic max-w-md mx-auto leading-relaxed">"{introMessage}"</p>
                <button 
                  onClick={startTurn} 
