               <div className="h-px bg-white/5 w-full"></div>
               <p className="text-sm leading-relaxed text-left text-slate-400">
                  {feedback.detailedDescription}
               </p>

               {feedback.videoUrl && (
                 <div className="mt-4">
                   <a 
                     href={feedback.videoUrl} 
                     target="_blank" 
                     rel="noopener noreferrer"
                     className="flex items-center justify-center gap-3 w-full py-4 bg-red-600 hover:bg-red-500 border border-red-400/30 rounded-xl transition-all group shadow-xl shadow-red-600/20"
                   >
                     <svg className="w-6 h-6 text-white group-hover:scale-110 transition-transform" fill="currentColor" viewBox="0 0 24 24"><path d="M19.615 3.184c-3.604-.246-11.631-.245-15.23 0-3.897.266-4.356 2.62-4.385 8.816.029 6.185.484 8.549 4.385 8.816 3.6.245 11.626.246 15.23 0 3.897-.266 4.356-2.62 4.385-8.816-.029-6.185-.484-8.549-4.385-8.816zm-10.615 12.816v-8l8 3.993-8 4.007z"/></svg>
                     <span className="font-black text-sm tracking-wider uppercase text-white">Watch Video Highlights</span>
                   </a>
