              <HistoryGallery history={history} />
            </div>
          </div>
        )}
      </main>

      <footer className="py-8 text-[10px] tracking-[0.5em] text-slate-600 uppercase font-black text-center opacity-40">
        AI Search Grounding Enabled • Sport-Sync 2025 • Pro Visuals
